// Generated by OrchestKit Claude Plugin
// Created: 2026-07-17

// Grouped display list for the ⌘K search dialog: a "Top results" row (top 3
// overall), then grouped sections (Guides / Concepts / Skills / Agents /
// Hooks / Other) capped per group. Items stay in ONE flat array so the
// dialog's arrow-key navigation works unchanged across group boundaries.

import { docTypeForUrl, stripOrigin } from "@/lib/search-relevance";

export type DisplayGroup =
	| "Guides"
	| "Concepts"
	| "Skills"
	| "Agents"
	| "Hooks"
	| "Other";

export function displayGroupForUrl(url: string): DisplayGroup {
	const path = stripOrigin(url);
	const type = docTypeForUrl(path);
	switch (type) {
		case "guide":
		case "cookbook":
			return "Guides";
		case "concept":
			// Concept pages about skills/agents/hooks group with their topic.
			if (path.startsWith("/docs/skills")) return "Skills";
			if (path.startsWith("/docs/agents")) return "Agents";
			if (path.startsWith("/docs/hooks")) return "Hooks";
			return "Concepts";
		case "skill":
			return "Skills";
		case "agent":
			return "Agents";
		case "hook":
			return "Hooks";
		case "reference":
		case "other":
			return "Other";
	}
}

const GROUP_ORDER: readonly DisplayGroup[] = [
	"Guides",
	"Concepts",
	"Skills",
	"Agents",
	"Hooks",
	"Other",
];

export const TOP_RESULTS_LABEL = "Top results";
const TOP_COUNT = 3;
const MAX_PER_GROUP = 4;

export type DisplayList<T> = {
	/** Flat, ordered item list (feeds keyboard navigation untouched). */
	items: T[];
	/** item id -> section header rendered ABOVE that item. */
	headerById: Record<string, string>;
};

/** Build the grouped display list from relevance-ordered page results. */
export function buildDisplayList<T extends { id: string; url: string }>(
	pages: readonly T[],
): DisplayList<T> {
	const items: T[] = [];
	const headerById: Record<string, string> = {};

	const top = pages.slice(0, TOP_COUNT);
	if (top.length > 0) {
		headerById[top[0].id] = TOP_RESULTS_LABEL;
		items.push(...top);
	}

	const grouped = new Map<DisplayGroup, T[]>();
	for (const page of pages.slice(TOP_COUNT)) {
		const group = displayGroupForUrl(page.url);
		const bucket = grouped.get(group) ?? [];
		if (bucket.length < MAX_PER_GROUP) {
			bucket.push(page);
			grouped.set(group, bucket);
		}
	}
	for (const group of GROUP_ORDER) {
		const bucket = grouped.get(group);
		if (!bucket || bucket.length === 0) continue;
		headerById[bucket[0].id] = group;
		items.push(...bucket);
	}

	return { items, headerById };
}
